SELECT MAX(metric_value) AS highest_accuracy
FROM solution_metrics
WHERE metric_name = 'accuracy';

SELECT AVG(num_arcs) AS average_arcs
FROM problem_solutions
WHERE solution_status = 'completed';

SELECT file_type 
FROM solution_files 
WHERE file_size = (SELECT MAX(file_size) FROM solution_files);

SELECT problem_id
FROM problem_tags
WHERE tag_name = 'portfolio_management';

SELECT description
FROM problems
WHERE user_id = 1;

SELECT run_time 
FROM problem_solutions 
WHERE solution_id = 1;

SELECT DISTINCT metric_name, metric_value
FROM solution_metrics
WHERE solution_id = 0;

SELECT problem_id 
FROM access_logs 
WHERE access_duration = (
  SELECT MAX(access_duration) 
  FROM access_logs
);
